#include <stdio.h>
#include <stdint.h>

const long long MOD = 1000000007LL;

long long modPow(long long base, long long exp) {
    long long res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, X;
        scanf("%lld %lld", &N, &X);
        long long pow = modPow(2, N - 1);
        long long ans = (X % MOD) * pow % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

